import React, { useState } from 'react';
import './App.css';
import Item from './component/Item';


function App() {
  const [items, setItems] = useState([{ name: "Phone", price: 1500, amount: 0 }, { name: "Laptop", price: 3500, amount: 0 }, { name: "Tablet", price: 2000, amount: 0 }, { name: "Smart Watch", price: 1000, amount: 0 }, { name: "Headphones", price: 500, amount: 0 }])
  const [total, setTotal] = useState(0)
  const [cart, setCart] = useState(false)
  const [totalCart, setTotalCart] = useState([])
  let addItem = (name) => {
    setItems(items.map((item) => {
      if (item.name == name) {
        setTotal(total + item.price)
        return { name: item.name, price: item.price, amount: (item.amount + 1) }
      }
      else return { name: item.name, price: item.price, amount: item.amount }
    }))
  }

  let delteItem = (name) => {
    setItems(items.map((item) => {
      if (item.name == name && item.amount > 0) {
        setTotal(total - item.price)
        return { name: item.name, price: item.price, amount: (item.amount - 1) }
      }
      else return { name: item.name, price: item.price, amount: item.amount }
    }))
  }

  let resetCart = () => {
    setItems(items.map((item) => {
      setTotal(0)
      return { name: item.name, price: item.price, amount: 0 }
        }
      )
    )
  }

let change = () => {
  if (!cart)
    setCart(true)
  else
    setCart(false)
}
let buy = (arr) => {
  setTotalCart(arr)

}
if (!cart) {
  return (
    <div >
      <h1>Sv- Shop</h1>
      <button on onClick={() => change()}>check out</button>
      <table>
        <tr class="table-header">
          <th>
            item name
          </th>
          <th>
            price
          </th>
          <th>
            amount
          </th>
          <th>
            Add to Cart
          </th>
          <th>
            Remove from cart
          </th>
        </tr>
        {items.map((i) => { return <Item info={i} add={addItem} remove={delteItem} /> })}
      </table>

    </div>
  );
}

else {
  return (
    <div>
      <h1>Check Out</h1>
      <button on onClick={() => change()}>return to the shop</button>
      <table>
        <tr class="table-header">
          <th>
            item name
          </th>
          <th>
            price
          </th>
          <th>
            amount
          </th>
          <th>
            Add to Cart
          </th>
          <th>
            Remove from cart
          </th>
        </tr>
        {items.filter(i => i.amount > 0).map((i) => { return <Item info={i} add={addItem} remove={delteItem} /> })}
      </table>
      <div> total :{total}</div>
      <button onClick={() => { buy(items.filter(i => i.amount > 0)) }}>
        Buy
      </button>
    </div>)
}
}
export default App;
